import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import {
  isValidCUID,
  validateStatusTransition,
  VALID_STATUSES,
} from "@/lib/validators";
import { broadcaster } from "@/lib/sse";

export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;

    if (!isValidCUID(id)) {
      return NextResponse.json(
        {
          error: "invalid_id",
          message: "Invalid request ID format",
        },
        { status: 400 }
      );
    }

    const requestRecord = await prisma.request.findUnique({
      where: { id },
    });

    if (!requestRecord) {
      return NextResponse.json(
        {
          error: "not_found",
          message: "Request not found",
        },
        { status: 404 }
      );
    }

    return NextResponse.json(
      {
        id: requestRecord.id,
        roomId: requestRecord.roomId,
        type: requestRecord.type,
        customNote: requestRecord.customNote,
        status: requestRecord.status,
        createdAt: requestRecord.createdAt.toISOString(),
        updatedAt: requestRecord.updatedAt.toISOString(),
      },
      { status: 200 }
    );
  } catch (error) {
    console.error("[GET /api/requests/[id]]", error);
    return NextResponse.json(
      {
        error: "server_error",
        message: "Internal server error",
      },
      { status: 500 }
    );
  }
}

export async function PATCH(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;

    if (!isValidCUID(id)) {
      return NextResponse.json(
        {
          error: "invalid_id",
          message: "Invalid request ID format",
        },
        { status: 400 }
      );
    }

    const body = await request.json();

    if (!body || typeof body !== "object") {
      return NextResponse.json(
        {
          error: "validation_error",
          message: "Request body must be a valid JSON object",
        },
        { status: 400 }
      );
    }

    const { status: newStatus } = body as Record<string, unknown>;

    if (!newStatus || typeof newStatus !== "string") {
      return NextResponse.json(
        {
          error: "validation_error",
          message: "status is required and must be a string",
        },
        { status: 400 }
      );
    }

    if (!VALID_STATUSES.includes(newStatus)) {
      return NextResponse.json(
        {
          error: "validation_error",
          message: `status must be one of: ${VALID_STATUSES.join(", ")}`,
        },
        { status: 400 }
      );
    }

    // Fetch existing request
    const existingRequest = await prisma.request.findUnique({
      where: { id },
    });

    if (!existingRequest) {
      return NextResponse.json(
        {
          error: "not_found",
          message: "Request not found",
        },
        { status: 404 }
      );
    }

    // Validate status transition
    const transitionValidation = validateStatusTransition(
      existingRequest.status,
      newStatus
    );

    if (!transitionValidation.valid) {
      return NextResponse.json(
        {
          error: "invalid_transition",
          message: transitionValidation.error,
          details: {
            from: existingRequest.status,
            to: newStatus,
          },
        },
        { status: 409 }
      );
    }

    // Update status
    const updatedRequest = await prisma.request.update({
      where: { id },
      data: { status: newStatus },
    });

    // Broadcast SSE event
    broadcaster.broadcast("request:update", {
      id: updatedRequest.id,
      roomId: updatedRequest.roomId,
      type: updatedRequest.type,
      customNote: updatedRequest.customNote,
      status: updatedRequest.status,
      createdAt: updatedRequest.createdAt.toISOString(),
      updatedAt: updatedRequest.updatedAt.toISOString(),
    });

    return NextResponse.json(
      {
        id: updatedRequest.id,
        roomId: updatedRequest.roomId,
        type: updatedRequest.type,
        customNote: updatedRequest.customNote,
        status: updatedRequest.status,
        createdAt: updatedRequest.createdAt.toISOString(),
        updatedAt: updatedRequest.updatedAt.toISOString(),
      },
      { status: 200 }
    );
  } catch (error) {
    console.error("[PATCH /api/requests/[id]]", error);
    return NextResponse.json(
      {
        error: "server_error",
        message: "Internal server error",
      },
      { status: 500 }
    );
  }
}

